#include <stdio.h>
#include <stdlib.h>
#define MAX_N 60

int count;
int max_len;
int K;
int adj[MAX_N][MAX_N];
int visited[MAX_N];

void dfs(int node, int parent, int len) {
    visited[node] = 1;
    int max_child_len = 0;
    for (int i = 0; i < MAX_N; i++) {
        if (adj[node][i] == 1 && i != parent) {
            dfs(i, node, len + 1);
            max_child_len = (max_child_len > max_len) ? max_child_len : max_len;
        }
    }
    if (max_child_len <= K) {
        count++;
    }
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d %d", &N, &K);
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < N; j++) {
                adj[i][j] = 0;
            }
        }
        for (int i = 0; i < N - 1; i++) {
            int u, v;
            scanf("%d %d", &u, &v);
            adj[u][v] = adj[v][u] = 1;
        }
        count = 0;
        for (int i = 0; i < N; i++) {
            max_len = 0;
            for (int j = 0; j < N; j++) {
                visited[j] = 0;
            }
            dfs(i, -1, 0);
        }
        printf("%d\n", count);
    }
    return 0;
}

