const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
let count = 0;
let max_len = 0;
let K = 0;
let adj = Array(60).fill(0).map(() => []);
let visited = Array(60).fill(0);

function dfs(node, parent, len) {
    visited[node] = 1;
    let max_child_len = 0;
    for (let child of adj[node]) {
        if (child !== parent) {
            dfs(child, node, len + 1);
            max_child_len = Math.max(max_child_len, max_len);
        }
    }
    if (max_child_len <= K) {
        count++;
    }
}

